style.css:
* {
    margin: 0;
    padding: 0;
    box-sizing: border-box
}

body {
    font-family: 'Segoe UI', Tahoma, Geneva, Verdana, sans-serif;
    background: #000;
    min-height: 100vh;
    display: flex;
    justify-content: center;
    align-items: center;
    position: relative;
    overflow: hidden
}

body::before {
    content: '';
    position: absolute;
    top: 0;
    left: 0;
    right: 0;
    bottom: 0;
    background: repeating-linear-gradient(0deg, rgb(255 255 255 / .03) 0, rgb(255 255 255 / .03) 1px, transparent 1px, transparent 2px);
    pointer-events: none;
    animation: noise 0.5s infinite
}

.demo-card h2 {
    text-align: center;
    margin-bottom: 50px;
    color: rgb(255 255 255 / .9);
    font-size: 2rem;
    font-weight: 300;
    letter-spacing: 4px;
    text-transform: uppercase;
    position: relative;
    text-shadow: 0 0 10px rgb(233 69 96 / .5), 0 0 20px rgb(233 69 96 / .3)
}

.demo-card h2::before,
.demo-card h2::after {
    content: attr(data-text);
    position: absolute;
    top: 0;
    left: 0;
    width: 100%;
    height: 100%;
    opacity: .3
}

.demo-card h2::before {
    color: #e94560;
    animation: glitch-title-1 2s infinite
}

.demo-card h2::after {
    color: #4e9eff;
    animation: glitch-title-2 2s infinite
}

.glitch-text {
    font-size: 20vw;
    font-weight: 900;
    color: #fff;
    text-shadow: 2px 2px 4px rgb(0 0 0 / .3), 0 0 20px rgb(233 69 96 / .5);
    position: relative;
    display: inline-block;
    animation: glitch-skew 4s infinite;
    letter-spacing: 10px;
    white-space: nowrap
}

.glitch-text::before,
.glitch-text::after {
    content: attr(data-text);
    position: absolute;
    top: 0;
    left: 0;
    width: 100%;
    height: 100%;
    background: #fff0
}

.glitch-text::before {
    animation: glitch-1 0.8s infinite linear alternate-reverse;
    color: #e94560;
    text-shadow: 2px 0 0 #4e9eff, -2px 0 0 lime;
    z-index: -1
}

.glitch-text::after {
    animation: glitch-2 0.8s infinite linear alternate-reverse;
    color: #4e9eff;
    text-shadow: 2px 0 0 #e94560, -2px 0 0 #ff0;
    z-index: -2
}

.scanline {
    position: fixed;
    top: -50vh;
    left: 0;
    width: 110vw;
    height: 200vh;
    background: linear-gradient(to bottom, transparent 50%, rgb(0 0 0 / .3) 50%);
    background-size: 100% 4px;
    pointer-events: none;
    animation: scanline 8s linear infinite;
    z-index: 1
}

.glitch-container {
    position: relative;
    padding: 40px
}

.glitch-container::before {
    content: '';
    position: absolute;
    top: -20px;
    left: -20px;
    right: -20px;
    bottom: -20px;
    background: radial-gradient(circle at 30% 50%, rgb(233 69 96 / .2) 0%, transparent 50%);
    filter: blur(40px);
    animation: glowPulse 3s infinite;
    z-index: -1
}

.glitch-container::after {
    content: '';
    position: absolute;
    top: 0;
    left: 0;
    right: 0;
    bottom: 0;
    border-radius: 20px;
    animation: borderGlitch 3s infinite
}

@keyframes glitch-skew {

    0%,
    100% {
        transform: skew(0deg)
    }

    2% {
        transform: skew(2deg)
    }

    4% {
        transform: skew(-2deg)
    }

    6% {
        transform: skew(1deg)
    }

    8% {
        transform: skew(-1deg)
    }

    10%,
    90% {
        transform: skew(0deg)
    }
}

@keyframes glitch-1 {

    0%,
    100% {
        clip-path: inset(0 0 0 0);
        transform: translate(0);
        opacity: .8
    }

    10% {
        clip-path: inset(20% 0 30% 0);
        transform: translate(-5px, 3px);
        opacity: 1
    }

    20% {
        clip-path: inset(10% 0 60% 0);
        transform: translate(5px, -3px);
        opacity: .6
    }

    30% {
        clip-path: inset(40% 0 40% 0);
        transform: translate(-5px, 5px);
        opacity: 1
    }

    40% {
        clip-path: inset(70% 0 10% 0);
        transform: translate(5px, -5px);
        opacity: .7
    }

    50% {
        clip-path: inset(30% 0 50% 0);
        transform: translate(-3px, 3px);
        opacity: .9
    }

    60% {
        clip-path: inset(50% 0 30% 0);
        transform: translate(3px, -3px);
        opacity: .5
    }

    70% {
        clip-path: inset(80% 0 10% 0);
        transform: translate(-4px, 4px);
        opacity: .8
    }

    80% {
        clip-path: inset(15% 0 70% 0);
        transform: translate(4px, -4px);
        opacity: 1
    }
}

@keyframes glitch-2 {

    0%,
    100% {
        clip-path: inset(0 0 0 0);
        transform: translate(0);
        opacity: .8
    }

    10% {
        clip-path: inset(60% 0 20% 0);
        transform: translate(5px, -3px);
        opacity: .6
    }

    20% {
        clip-path: inset(30% 0 50% 0);
        transform: translate(-5px, 3px);
        opacity: 1
    }

    30% {
        clip-path: inset(10% 0 70% 0);
        transform: translate(5px, -5px);
        opacity: .7
    }

    40% {
        clip-path: inset(40% 0 40% 0);
        transform: translate(-5px, 5px);
        opacity: .9
    }

    50% {
        clip-path: inset(70% 0 10% 0);
        transform: translate(3px, -3px);
        opacity: .5
    }

    60% {
        clip-path: inset(20% 0 60% 0);
        transform: translate(-3px, 3px);
        opacity: 1
    }

    70% {
        clip-path: inset(50% 0 30% 0);
        transform: translate(4px, -4px);
        opacity: .8
    }

    80% {
        clip-path: inset(80% 0 10% 0);
        transform: translate(-4px, 4px);
        opacity: .6
    }
}

@keyframes glitch-title-1 {

    0%,
    100% {
        transform: translate(0);
        opacity: .3
    }

    20% {
        transform: translate(-2px, 1px);
        opacity: .5
    }

    40% {
        transform: translate(2px, -1px);
        opacity: .2
    }

    60% {
        transform: translate(-1px, 2px);
        opacity: .4
    }

    80% {
        transform: translate(1px, -2px);
        opacity: .3
    }
}

@keyframes glitch-title-2 {

    0%,
    100% {
        transform: translate(0);
        opacity: .3
    }

    20% {
        transform: translate(2px, -1px);
        opacity: .4
    }

    40% {
        transform: translate(-2px, 1px);
        opacity: .2
    }

    60% {
        transform: translate(1px, -2px);
        opacity: .5
    }

    80% {
        transform: translate(-1px, 2px);
        opacity: .3
    }
}

@keyframes noise {

    0%,
    100% {
        transform: translate(0, 0)
    }

    10% {
        transform: translate(-1%, -1%)
    }

    20% {
        transform: translate(1%, 1%)
    }

    30% {
        transform: translate(-1%, 1%)
    }

    40% {
        transform: translate(1%, -1%)
    }

    50% {
        transform: translate(-1%, -1%)
    }

    60% {
        transform: translate(1%, 1%)
    }

    70% {
        transform: translate(-1%, 1%)
    }

    80% {
        transform: translate(1%, -1%)
    }

    90% {
        transform: translate(-1%, -1%)
    }
}

@keyframes scanline {
    0% {
        transform: translateY(-10%)
    }

    100% {
        transform: translateY(10%)
    }
}

@keyframes glowPulse {

    0%,
    100% {
        opacity: .5;
        transform: scale(1)
    }

    50% {
        opacity: .8;
        transform: scale(1.1)
    }
}

@keyframes borderGlitch {

    0%,
    100% {
        transform: scale(1)
    }

    25% {
        transform: scale(1.02)
    }

    50% {
        transform: scale(.98)
    }

    75% {
        transform: scale(1.01)
    }
}

@media (max-width:768px) {
    .demo-card {
        padding: 30px 40px;
        margin: 20px
    }

    .glitch-text {
        letter-spacing: 5px
    }

    .demo-card h2 {
        font-size: 1.5rem;
        letter-spacing: 2px
    }
}

@media (max-width:480px) {
    .glitch-text {
        letter-spacing: 3px
    }
}

.glitch-text:hover {
    animation: glitch-skew 1s infinite
}

.glitch-text:hover::before {
    animation-duration: 0.3s
}

.glitch-text:hover::after {
    animation-duration: 0.3s
}

.copy {
	position: fixed;
	bottom: 20px;
	right: 20px;
	color: #000;
	background: rgb(255 255 255 / 0.9);
	padding: 10px;
	border-radius: 5px;
	font-size: 12px;
	transition: all .8s ease;
	z-index:100;
	cursor: pointer;
}

.copy:hover {
	color: #fff;
	background: rgb(0 0 0 / 0.9);
	transition: all .8s ease;
}
